    public boolean canPartitionKSubsets(int[] nums, int k) {
        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k != 0) return false;
        int target = sum / k;
        Arrays.sort(nums);
        return dfs(nums, k, target, 0, new boolean[nums.length]);
    }
    private boolean dfs(int[] nums, int k, int target, int start, boolean[] used) {
        if (start == nums.length) return true;
        for (int i = start; i < nums.length; i++) {
            if (used[i] || nums[i] > target) continue;
            if (nums[i] == target) {
                used[i] = true;
                if (dfs(nums, k, target, i + 1, used)) return true;
                used[i] = false;
            } else {
                int j = i;
                while (j < nums.length && nums[j] <= target) {
                    used[j] = true;
                    if (dfs(nums, k, target - nums[j], j + 1, used)) return true;
                    used[j] = false;
                    j++;
                }
            }
        }
        return false;
    }
}
